/// <summary>
/// Open Vendor import
/// </summary>
public class ETG_Acu_OpenVendInvoiceImport extends ETG_Acu_DataImportBase
{
    LedgerJournalId         journalNum;

}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_OpenVendInvoiceImport  openVendInvoiceImport;

    openVendInvoiceImport = ETG_Acu_OpenVendInvoiceImport::construct();

    if (openVendInvoiceImport.prompt())
    {
        openVendInvoiceImport.runOperation();
    }
}

public static ETG_Acu_OpenVendInvoiceImport construct()
{
    return new ETG_Acu_OpenVendInvoiceImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    LedgerJournalEntity                     ledgerJournal;
    VendTable                               vendTable;
    DirPartyBaseEntity                      vendTableDirParty;

    select firstonly vendTable
        exists join vendTableDirParty
            where vendTableDirParty.PartyRecordId ==  vendTable.Party
                && vendTableDirParty.OrganizationNumber == conpeek(_con, 3);

    NumberSeq               numberSeq;

    if (!journalNum)
    {
        numberSeq = NumberSeq::newGetNum(LedgerParameters::numRefJournalNum());

        journalNum = numberSeq.num();
    }

    ledgerJournal.JournalBatchNumber            = journalNum;
    ledgerJournal.LineNumber                    = conpeek(_con, 2);
    ledgerJournal.AccountDisplayValue           = vendTable.AccountNum;
    ledgerJournal.AccountType                   = LedgerJournalACType::Vend;
    ledgerJournal.CreditAmount                  = conpeek(_con, 5);
    ledgerJournal.CurrencyCode                  = conpeek(_con, 6);
    ledgerJournal.DebitAmount                   = conpeek(_con, 7);
    ledgerJournal.DefaultDimensionDisplayValue  = conpeek(_con, 8);
    ledgerJournal.Description                   = conpeek(_con, 9);
    ledgerJournal.Document                      = conpeek(_con, 10);
    ledgerJournal.DueDate                       = conpeek(_con, 11);
    ledgerJournal.ExchangeRate                  = conpeek(_con, 12);
    ledgerJournal.Invoice                       = conpeek(_con, 13);
    ledgerJournal.InvoiceDate                   = conpeek(_con, 14);
    ledgerJournal.JournalName                   = conpeek(_con, 15);

    ledgerJournal.OffsetAccountDisplayValue     = conpeek(_con, 16) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 27) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 25) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 29) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 28) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 23) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 26) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                    + conPeek(_con, 24);

    ledgerJournal.OffsetAccountType             = conpeek(_con, 17);
    ledgerJournal.PostingLayer                  = conpeek(_con, 18);
    ledgerJournal.PostingProfile                = conpeek(_con, 19);
    ledgerJournal.Text                          = conpeek(_con, 20);
    ledgerJournal.TransDate                     = str2Date(conpeek(_con, 21), 123);

    // BusinessUnit (23)	Contract (24)	Department (25)	Intercompany (26)	Plant_Warehouse_Office (27)	Product_Service (28)	Trader_Employee (29)
    // |Plant_Warehouse_Office|Department|Trader_Employee|Product_Service|BusinessUnit|Intercompany|Contract

    ledgerJournal.DefaultDimensionDisplayValue  = conPeek(_con, 27) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 25) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 29) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 28) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 23) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 26) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 24);

    ledgerJournal.insert();
}

/// <summary>
///Import inventory site
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImpOpenVendInv";

    return ret;
}
